const Q_PHYSICS_2010=[{"id": "objective>Physics>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject is this? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject of the questions is Physics. This can be determined from the context of the questions which are all related to Physics concepts.</div>", "topic": "INTRODUCTION"}, {"id": "objective>Physics>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two cars moving in the same direction have speeds of 100kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and 130kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. <br/> What is the velocity of the faster car as  measured by an observer in the slower car?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">130kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">230kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This question tests the concept of relative velocity <br/> <img src=\"2010/1.png\" style=\"position:relative;max-width:100%;\"/> <br/> <img src=\"2010/2.png\" style=\"position:relative;max-width:100%;\"/> <br/> The velocity of the faster car (A) as measured by the observer in the slower car (B), V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">AB</span> = (130 - 100)kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">AB</span> = 30kmh<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "SCALARS AND VECTORS : RELATIVE VELOCITY"}, {"id": "objective>Physics>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above shows a velocity-time graph. <br/>  The statement that is true about this motion is that, the car</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decelerates between points F and H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accelerates between points F and G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a constant speed between points E and F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has no acceleration between point F and G</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let us analyse the graph properly: <br/> * Between E and F, the car experiences an increase in its velocity over a given time interval (acceleration) <br/> * Between F and G, the car maintains a constant velocity (zero acceleration) <br/> * Between G and H, the car experiences a decrease in its velocity over a given time interval (deceleration) <br/> </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A stone and a feather dropped from the same height above the earth surface. Ignoring air resistance, which of the following is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The stone and feather will both reach the ground at the same time.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The stone will reach the ground first</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The feather will reach the ground first</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The feather will be blown away by the wind while stone will drop steadily.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Galileo Galilei (1564 - 1642), when two objects of different masses are dropped from a height, in the absence of air resistance, the two object will get to the ground at the same time (irrespective of their masses).</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car moves with an initial velocity of 25ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and reaches a velocity of  <br/> 45ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>in 10s.  <br/>  What is the acceleration of the car?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">25ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Initial Velocity, u = 25.0m/s <br/> Final Velocity, v = 45.0m/s <br/> Time, t = 10.0s <br/> Acceleration, a = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v-u<hr size=\"1\" />t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">45-25<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div></div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is weighed at different locations on the earth. <br/> What will be the right observation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both the mass and weight vary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The weight is constant while the mass varies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mass is constant while the weight varies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both the mass and weight are constant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From, W = mg --------------- (i) <br/> W α g <br/> m = constant <br/> W → Weight <br/> m → mass <br/> g → acceleration due to gravity. <br/> Note that the mass of a body is constant everywhere whereas, the weight of a body varies from place to place due to the variation in the value of the acceleration due to gravity (g)</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above represents balls in an undulating surface.  <br/>  Which of the following option represent position of stable equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II, V and VIII</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, IV, VII</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III, VI and IX</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III, IV and VIII</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that at points (iii), (vi) and (ix), the body is at points of stable equilibrium. <br/> Note: When a body is in stable equilibrium, if displaced slightly, it will still remain at its original position.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bob of weight 0.1N hangs from a massless string of length 50cm. A variable <br/> horizontal force which increases from zero is applied to pull the bob until the <br/> string makes an angle of 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> with the vertical.  <br/>  The work done is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.250 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.025J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.050 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.500 J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> (i) <img src=\"2010/3.png\" style=\"position:relative;max-width:100%;\"/> <br/> (ii) <img src=\"2010/4.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: Workdone = Force × Distance moved in the direction of the applied force  <br/> <img src=\"2010/5.png\" style=\"position:relative;max-width:100%;\"/> <br/>   Workdone = Force x distance  <br/>  = 0.1 x 0.5 x 0.5 <br/> = 0.025J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The surfaces of conveyor belts are made rough so as to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent the load from slipping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make them stronger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enable them to carry more load</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect them while carrying load.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The surfaces of conveyor belts are made rough so as to prevent the load from slipping. <br/> Note that this is an advantage of friction.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine of velocity ratio 6 requires an effort of 400N to raise a load of  <br/> 800N through 1 m. Find the efficiency of the machine.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.2%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.3%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">55.6%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Velocity Ratio, V.R = 6.0 <br/> Effort, E = 400N <br/> Load, L = 800N <br/> Distance moved by load = 1m <br/> Efficiency = ? <br/> Recall:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M.A<hr size=\"1\" />V.R</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M.A</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Load (L)<hr size=\"1\" />Effort (E)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">800<hr size=\"1\" />400</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.0</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />6</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">33.3%</td></tr></table></div></div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a wire 30cm long is extended to 30.5cm by a force of 300N.  <br/>  Find the strain energy of the wire.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.50 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">750.00 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75.00 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.75 J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Original length, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 30cm <br/> Final length, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> = 30.5cm <br/> Force, F = 300N <br/> Energy, E = ? <br/> <img src=\"2010/6.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: E = 1/2 Fe ------------------ (1) <br/> e = L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> - L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> ------------------- (2) <br/> e = 30.5 - 30.0 = 0.5cm = 0.005m <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">300</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.005</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">0.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.75J</td></tr></table></div></div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a hydraulic press, the pump piston exerts a pressure of 100 Pa on the liquid.What force is exerted in the second piston of cross-sectional area;  <br/> 3m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300 N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that a hydraulic press obeys the <span style=\"font-weight:bold;font-style:italic;\"> \"principle of transmissibility of pressure\". </span> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> We are given P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to be 100pa <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />3</td></tr></table></div> <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 300N</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The accurate measurement of the relative density of a substance in its powdered form is done with a beam balance and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an eureka can</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a burette</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pipette</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a density bottle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The accurate measurement of the relative density of a substance in its powdered form is done with a beam balance and a density bottle.</div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hydrometer is an instrument used in measuring</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">density of liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative density of a liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative humidity of a liquid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vapour pressure of a fluid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hydrometer is an instrument used in measuring the relative density of a liquid. Relative density, or specific gravity, is the ratio of the density (mass of a unit volume) of a substance to the density of a given reference material. A hydrometer works on the principle of buoyancy, where the stem of the hydrometer is calibrated to give a numerical reading.</div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One special advantage of alcohol over mercury as a thermometric  <br/> liquid is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low freezing point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high specific heat capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low density</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A special advantage of alcohol over mercury as a thermotric liquid is its low freezing point hence suitable for low temperatures.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two metals P and Q of lengths l1 and l2 are heated through the same temperature difference.  <br/>  If the ratio of the linear expansitivities of P to Q is 2 : 3 and the ratio of their lengths is 3 : 4; what is the ratio of increase in lengths of P to Q?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 : 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 : 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 : 5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> <span style=\"font-weight:bold;text-decoration:underline;\"> Metal P </span> <br/> Original length, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 3(ratio) <br/> Temperature difference = Δθ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> <br/> Linear expansivity, α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 2 (ratio) <br/> Increase in Length, (L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> <br/> <span style=\"font-weight:bold;text-decoration:underline;\"> Metal Q </span> <br/> Original length, L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4(ratio) <br/> Temperature difference = Δθ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> <br/> Linear expansivity, α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> = 3(ratio) <br/> Increase in length, (L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> = ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> <br/>  <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔL<hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td></tr></table></div> <br/> αL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ = ΔL <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Δθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔL<hr size=\"1\" />αL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div> <br/> N.B: Δθ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = Δθ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span><hr size=\"1\" />α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> × α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span><hr size=\"1\" />ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> × α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div></div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The density of a certain oil on frying becomes 0.4kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> with a volume of 20m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>.  <br/>  What will be its initial volume when its initial density is 0.8kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> assuming no loss of oil due to spillage?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NOTE: During boiling, frying etc <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (mass is constant) <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">h</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">h</span> = mass of heat <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = mass of cold <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Density,</td><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<hr size=\"1\" />v</td></tr></table></div> <br/> ρ × v = m <br/> ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">h</span> × v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">h</span> = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> × v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> <br/> 0.4 × 20 = 0.8 × v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8<hr size=\"1\" />0.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10.0kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div></div>", "topic": "LIQUIDS AT REST : DENSITY OF SOLID AND LIQUIDS"}, {"id": "objective>Physics>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Heat is radiated by all hot objects in the form of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solar energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infrared ray</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x-rays.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat is radiated by all hot objects in the form of infrared rays. This is a basic principle of thermodynamics. Infrared radiation is a type of electromagnetic radiation, as are light, x-rays, and radio waves. However, the specific type of radiation that is most commonly associated with heat is infrared.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a container is filled with ice to the brim,what happens to the level of  <br/> water when the ice completely melts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The water in the glass outflows</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The level of water drops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The level of water remains unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The level of water goes up</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The level of water remains unchanged as the ice already displaces its own volume of the liquid in which it floats.</div>", "topic": "CHANGE OF STATE : MELTING"}, {"id": "objective>Physics>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The small droplet of water that forms on the grass in the early hours of the morning is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dew</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fog</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hail</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dew is the small droplets of water that forms on cool surfaces in the early hours of the morning due to condensation.</div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A vapour is said to be saturated when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a dynamic equilibrium exists such that more molecules return to the liquid <br/> than are leaving it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the vapour pressure is atmospheric</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the temperature of the vapour varies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dynamic equilibrium exists between the molecules of the liquid and the vapour molecules at a given temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A vapour is said to be saturated when a dynamic equilibrium exists between liquid molecules and the vapour  molecules. </div>", "topic": "VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure of one mole of an ideal gas of volume 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>at a temperature of 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C is   <br/>  [Molar gas constant = 8.3 Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.24 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.24 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.49 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.49 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Pressure, P = ? <br/> Volume, V = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Temperature, T = 27°C <br/> Molar gas constant = 8.3Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Recall: <br/> Pv = nRT <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">nRT<hr size=\"1\" />V</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.0 × 8.3 × 300<hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td></tr></table></div> <br/> P = 300 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 8.3 <br/> P= 8.3 x 3 x 10^4 <br/> P=24.9 x 10^4 <br/> P= 2.49 x 10 ^5 <br/> P= 2.49 x 10^5 Nm^-2</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has no effect on radiation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of the surface</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Radiation is a method of heat transfer that does not require a medium, and therefore is not affected by the density of the medium. It is affected by the temperature of the object (higher temperature objects emit more radiation), the surface area (larger objects emit more radiation), and the nature of the surface (darker and rougher surfaces emit more radiation). Therefore, the density has no effect on radiation, which matches option 1.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The wavelength of a wave travelling with a velocity of 420ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is 42 m.   <br/>  What is its period?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Velocity, V = 420ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Wavelength, λ = 42.0m <br/> Period, T = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Velocity,</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Wavelength (λ)<hr size=\"1\" />Period (T)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">420</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">42<hr size=\"1\" />T</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">42<hr size=\"1\" />420</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.1s</td></tr></table></div></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sound of an electric bell dies down slowly when air is slowly pumped out from a bottle because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sound cannot pass through the bottle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sound can pass through a vacuum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sound needs a material medium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the wavelength of sound becomes greater in the bottle</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sound of an electric bell dies down as air is being pumped out because sound needs a material medium for its propagation.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During a thunderstorm, the sound is heard over a long time.  <br/>  This phenomenon is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">refraction of sound</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reverberation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">superposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction of sound.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon of hearing sound over a long time during a thunderstorm is referred to as reverberation. Reverberation is the persistence of sound after the sound is produced. It occurs because the sound waves are reflected multiple times before they are absorbed.</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity of sound in air at 16<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C is 340ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.  <br/>  What will it be when the pressure is doubled and its temperature raised to 127<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4,000ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">160,000 ms(-1)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8,000 ms(-1)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Initial velocity, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 340ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Initial temperature, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 16°C = 289K <br/> Final temperature, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 127°C = 400K <br/> Final velocity, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> The question says <br/> \"Pressure is doubled\", but note that pressure does not affect the velocity of sound in air. <br/> Recall: V α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">340<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">289&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">400&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">340<hr size=\"1\" />17</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />20</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 20 × 20 = 400ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In comparing the camera and the human eye, the film of the camera functions as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iris</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pupil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cornea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retina</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a camera, the film or image sensor is where the image is formed, just like the retina in the human eye. The retina is the part of the eye where the image is formed, it is a light-sensitive layer of tissue. The iris, pupil, and cornea are parts of the eye that help control the amount of light that enters and focus it onto the retina, but they do not capture the image.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object 4 cm high is placed 15 cm from a concave mirror of focal length 5 cm. <br/>  <br/>  The size of the image is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Object high, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 4.0cm <br/> Object distance, u = 15cm <br/> Focal length, f= 5cm <br/> Image size, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span> (or image height) = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">v<hr size=\"1\" />u</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span><hr size=\"1\" />H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">-----------------------------</td><td style=\"text-align:center;\">(i)</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />15</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />5</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />5</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1<hr size=\"1\" />15</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(3-1)<hr size=\"1\" />15</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />15</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15<hr size=\"1\" />2</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7.5cm</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> From (i) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">7.5<hr size=\"1\" />15</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span><hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.0cm.</td></tr></table></div></div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : USE OF THE MIRROR FORMULA"}, {"id": "objective>Physics>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is embedded in a block of ice, 10cm below the plane surface. If the refractive index of the ice is 1.50, the apparent depth of the object  <br/> below the surface is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.67 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.63 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.50 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50 cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Refractive index, η = 1.50 <br/> Real depth, r = 10cm <br/> Apparent depth, a = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall;</td><td style=\"text-align:center;\">Refractive</td><td style=\"text-align:center;\">index,</td><td style=\"text-align:center;\">η</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">real depth<hr size=\"1\" />apparent depth</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1.50</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />a</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />1.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.67cm</td></tr></table></div></div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used for the correction of short-sightedness?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Concave lens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Concave mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convex mirror</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convex lens</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Short-sightedness, also known as myopia, is a common vision condition in which you can see objects near to you clearly, but objects farther away are blurry. It can be corrected using a concave lens. A concave lens is a lens that possesses at least one surface that curves inwards. It is a diverging lens, meaning it spreads out light rays that have been refracted.</div>", "topic": "OPTICAL INSTRUMENTS : SIGHT DEFECTS AND THEIR CORRECTIONS"}, {"id": "objective>Physics>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersion occurs when white light passes through a glass prim because of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">different speeds of the colours in the glass.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high density of the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defects in the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different hidden colours in the glass</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersion of the colours of white light is due to the different speeds of the columns in the glass.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a positively charged rod is brought nearer the cap of a positively charged electroscope, the leaves divergence will.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">converge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diverge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be induced.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a positively charged rod is brought nearer the cap of a positively charged electroscope, more electrons move towards the charged rod (attraction) making the gold leaf and the metal stem in the electroscope to be less negatively charged (i.e more positively charged). So the metal stem and the gold leaf being more positively charged more farther away (diverge).</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three capacitors of capacitance, 2μF, 4μF and 8μF are connected in parallel and a p.d of 6V is maintained across each capacitor, the total energy stored is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.90 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.90 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.52 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.52 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2010/7.png\" style=\"position:relative;max-width:100%;\"/> <br/> * Note that when capacitors are arranged in parallel, the effective capacitance is the direct arithmetic sum of the capacitances of the capacitors <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> {Parallel} <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 8 + 4 + 2 = 14μF ---------------------------------------------- (i) <br/> * Also note that when capacitors are arranged in parallel, they normally have the same potential difference,  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 6v <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">CV<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">14</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">14</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">36</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td></tr></table></div> <br/> E = 7 × 36 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> <br/> E = 2.52 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>J</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cell of emf 12V and internal resistance 4Ω  Ω is connected to an external resistor of resistance 2Ω  Ω. Find the current flow.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 A</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> E.m.f, E = 12v <br/> Internal resistance, r = 4Ω <br/> Resistor, R = 2Ω <br/> Current, I = ? <br/> Recall: E = I(R + r) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />4+2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2A</td></tr></table></div></div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above shows a balanced metre bridge, the value of x is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">66.7 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.0 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.3 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75.0 cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total resistance of parallel arrangement  <br/>  = (8x8)/(8+8)   = 64/16   = 4ω   <br/>  ∴  R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  =   R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  4/x  = 8/(100-x) ∴ 8x = 400-4x.  12x = 400  <br/>  ∴ x =  400/12   = 100/3    = 33.3cm.  </div>", "topic": "CURRENT ELECTRICITY : METER BRIDGE"}, {"id": "objective>Physics>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three 4 Ω resistors connected in parallel have a potential difference of  <br/> 16V applied across them.  <br/> What is the total current in the circuit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14 A</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2010/8.png\" style=\"position:relative;max-width:100%;\"/> <br/> Note that since the resistors are in parallel, they have the same potential difference <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />3</td><td style=\"text-align:center;\">Ω</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 16V <br/> Recall: V = IR <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">16</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16×3<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12.0A</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  In the diagram above, a 200 W bulb is lighted by a 240 V a.c mains supply. If 1kWh is sold at N 40, the cost of keeping the bulb lighted for a day is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N 192.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 1.92</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 19.20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N 1,920.00.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters gien: <br/> Voltage, v = 240v <br/> Power, P = 200w <br/> 1kwh = ₦40 <br/> Time, t = 1day = 24 hours <br/> Recall: Energy = Power × Time <br/> E = 0.2 kw × 24hr <br/> E = 4.8 kWh ---------------------- (i) <br/> N.B: 1kWh = ₦40 <br/> 4.8kWh = x <br/> x = ₦192.00 <br/> x = ₦192.00</div>", "topic": "ELECTRICAL ENERGY AND POWER : COMMERCIAL UNIT OF ELECTRIC ENERGY AND POWER"}, {"id": "objective>Physics>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Power supply is transmitted at a very high voltage and low current in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the power supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent overheating of the coil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make it travel fast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make it pass through the <br/> transformers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Power supply is transmitted at a very high voltage and low current in order to prevent overheating of the coil.</div>", "topic": "ELECTRICAL ENERGY AND POWER : ELECTRIC POWER TRANSMISSION"}, {"id": "objective>Physics>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  In the diagram above, if the south -poles of two magnets stroke a steel bar, the polarities at T and V will respectively be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">north and south</div>", "<div style=\"font-family:Cambria;font-size:17px;\">south and south</div>", "<div style=\"font-family:Cambria;font-size:17px;\">north and north</div>", "<div style=\"font-family:Cambria;font-size:17px;\">south and north</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The polarities at T and V would be north and north.  <br/>  This is because the end of the bar acquires pole(s) opposite that of the stroking pole.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A galvanometer with full-scale deflection of 10 mA is to be converted to a <br/> voltmeter with full-scale deflection of 5 V. <br/> If a series resistance of 498Ω is used for the conversion, the resistance of the galvanometer is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 Ω</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">r = resistance of the galvanometer <br/> l = current through galvanometer = 10mA = 0.01A <br/>  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = p.d across the galvanometer = I &#215; r = 0.01r <br/>  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> =  p.d across the  multiplier = 5 - 0.01r <br/>  <br/> R = resistance of the multiplier = 498Ω <br/>  <br/> But V = IR <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />I</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">498</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5 - 0.01r<hr size=\"1\" />0.01</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4.98</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">0.01r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.01r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">4.98</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">0.01r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.02</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.02<hr size=\"1\" />0.01</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">Ω</td></tr></table></div></div>", "topic": "MAGNETIC FIELD : CONVERSION OF GALVANOMETERS TO AMMETERS AND VOLTMETER"}, {"id": "objective>Physics>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two inductors of inductances 5 mH and 15 mH are connected in series and a current of 5 A flows through them. The total energy stored in the inductors is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25 J    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05 J  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.0625 J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E = 1/2 LI<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> =  ½ ( 15 + 5) (5)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = ½ x 20 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> x 25  <br/>  <br/>  = 500/2  x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> = 250 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> J.</div>", "topic": "ELECTROMAGNETIC INDUCTION : ENERGY STORED IN AN INDUCTOR"}, {"id": "objective>Physics>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In alternating current circuit at resonance, the angle of lead or lag is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">π<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span><hr size=\"1\" /> 2</td></tr></table></div> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">π<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span><hr size=\"1\" /> 3</td></tr></table></div> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">π<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an alternating current circuit at resonance, the circuit is purely resistive. This means that the current and voltage are in phase with each other, and there is no phase difference. The angle of lead or lag, which represents the phase difference between current and voltage, is therefore 0 degrees.</div>", "topic": "SIMPLE A. C. CIRCUITS : RESONANCE AND RESONANCE FREQUENCY"}, {"id": "objective>Physics>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Faraday's law of electrolysis, a graph of mass deposited against the quantity of electricity is plotted  <br/>  The slope of the graph gives</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the electrochemical equivalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the charge released</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the current flowing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the energy released</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Faraday First Law of Electrolysis, <br/> m α Q ---------------- (i) <br/> m α It <br/> m = KIt ------------------------- (ii) <br/> Note: k = Z (Electrochemical equivalent) <br/> ∴ m = ZQ <br/> y = mx <br/> slope (m) = Z</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a discharge tube, most of the gas is pumped out so that electricity is conducted at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steady voltage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low voltage</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a discharge tube experiment, most of the gas is pumped out so that electricity is conducted at low pressure. </div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The radioisotope  <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">235</span><span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">92</span>∪ decays by emitting two alpha particles, three beta particles and a gamma ray. <br/>  What is the mass and atomic numbers of the resulting daughter element?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">91 and 227</div>", "<div style=\"font-family:Cambria;font-size:17px;\">92 and 238</div>", "<div style=\"font-family:Cambria;font-size:17px;\">227 and 91</div>", "<div style=\"font-family:Cambria;font-size:17px;\">215 and 88.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the question, we have: <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U → 2α + 3β + 1γ + X <br/> N.B: α = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He <br/> β = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e <br/> γ = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n <br/> let X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>X <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U → 2. <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He + 3(<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e) + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>X <br/> 235 = 8 + 0 + 0 + a <br/> a = 227 <br/> Also: 92 = 4 - 3 + 0 + b <br/> ∴ b = 91 <br/> ∴ <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">227</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">91</span>X <br/> </div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ground state energy for a hydrogen atom is 5.44 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J.  <br/>  If an electron drops from zero to ground state, calculate the frequency of the emitted radiation  <br/>  [h = 6.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.24 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span>Hz</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> Energy, E = 5.44 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>J <br/> Planck's Constant, h = 6.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js <br/> Frequency, F = ? <br/> Recall: E = hf ----------------- (i) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5.44 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span><hr size=\"1\" />6.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.824</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span></td></tr></table></div> <br/> f = 8.24 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "topic": "ELEMENTARY MODERN PHYSICS : ENERGY LEVELS AND SPECTRA"}, {"id": "objective>Physics>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Transistors are used for the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conversion of a.c. to d.c.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conversion of d.c. to a.c.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amplification of signals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rectification of signals.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transistors are used for the amplification of signals. A transistor is used for amplification of signals by raising the strenght of a weak signal.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}, {"id": "objective>Physics>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A typical transistor characteristic is represented as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A typical transistor characteristics is represented by  <br/>  <img src=\"2010/cs3.png\" style=\"position:relative;max-width:100%;\"/>.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}, {"id": "objective>Physics>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a pure semi-conductor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Silicon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phosphorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transistor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silicon is a pure semiconductor. A semiconductor is a substance, usually a solid chemical element or compound, that can conduct electricity under some conditions but not others, making it a good medium for the control of electrical current. Silicon is one of the best-known of these substances and makes up about 28% of the earth's crust.</div>", "topic": "INTRODUCTORY ELECTRONICS"}];
